mapper.select:
select mlable.name from kb_basic_label label join kb_basic bs on bs.id = label.b_id join kb_model_label mlable on mlable.id = label.l_id join kb_category ct on ct.id = bs.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id and au.status = 2 left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) and au.status = 3 join castle_sys_user user on (au.user_id = user.id or (user.id = groupu.user_id) or (user.dept_id = dept.id)) where user.id= #{uid} and au.kb_auth in (
#{kb_auth}
) group by mlable.name order by count(1) desc limit #{TopNum}

